// Generated by OrchestKit Claude Plugin
// Created: 2026-04-17

/**
 * Stale Import Detector - PostToolUse/Write hook
 *
 * Source: usage analytics #3 friction point — file splits and renames leave
 * stale import paths in tests that cascade-fail on the next run. Existing
 * affected-tests-finder suggests tests to RUN, not stale imports to FIX.
 *
 * Trigger: After a Write tool call creates a NEW file, or after the hook
 * detects that a previously-existing file is gone from disk. We grep the
 * repo for imports that still reference the old path (inferred from the
 * new file's neighbours) and inject a context advisory listing the stale
 * import sites.
 *
 * This is advisory — never blocks — because false positives would derail
 * legitimate refactors. The additionalContext is small and skippable.
 */

import { existsSync } from 'node:fs';
import { execSync } from 'node:child_process';
import { dirname, basename, relative, sep } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputNotify, getField } from '../../lib/common.js';
import { assertSafeShellArg } from '../../lib/sanitize-shell.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'posttool/write/stale-import-detector';

// Extensions we understand import-wise
const CODE_EXT_RE = /\.(ts|tsx|js|jsx|mjs|cjs|py)$/;

// Max stale references to list in the advisory (clip to avoid context bloat).
const MAX_REFS = 10;

// Skip tiny results — single references are usually legitimate.
const MIN_SIGNAL_REFS = 2;

/**
 * Given a file path, derive the module identifier that imports would use.
 * Handles both TS/JS (path-relative, no extension) and Python (dotted path).
 */
function deriveModuleId(projectDir: string, filePath: string): {
  lang: 'ts' | 'py' | null;
  bareName: string;
  pathHint: string;
} {
  const rel = relative(projectDir, filePath);
  if (filePath.endsWith('.py')) {
    // Python dotted path: backend/app/services/auth.py -> app.services.auth
    const noExt = rel.replace(/\.py$/, '');
    const parts = noExt.split(sep).filter(p => p && p !== '__init__');
    return { lang: 'py', bareName: basename(noExt), pathHint: parts.join('.') };
  }
  if (CODE_EXT_RE.test(filePath)) {
    // TS/JS: strip extension, use basename for named imports
    const noExt = rel.replace(CODE_EXT_RE, '');
    return { lang: 'ts', bareName: basename(noExt), pathHint: noExt };
  }
  return { lang: null, bareName: '', pathHint: '' };
}

/**
 * Grep the codebase for imports that reference a possibly-stale path.
 * Returns file:line hits capped at MAX_REFS.
 */
function findStaleReferences(
  projectDir: string,
  lang: 'ts' | 'py',
  pathHint: string,
): string[] {
  if (!pathHint) return [];

  // Pattern choice per language:
  //  - TS/JS: match from or require calls referencing the derived module id
  //  - Python: match from/import statements referencing the dotted module id
  let pattern: string;
  if (lang === 'ts') {
    // The meaningful fragment is the last 2 path segments (survives prefix differences).
    const segments = pathHint.split('/').filter(Boolean).slice(-2).join('/');
    if (!segments) return [];
    pattern = `(from|require\\(|import\\().*${segments}`;
  } else {
    // Python: `app.services.auth` -> look for exact dotted path
    const safe = pathHint.replace(/\./g, '\\.');
    pattern = `(from\\s+${safe}\\s+import|import\\s+${safe})`;
  }

  try {
    const safeDir = assertSafeShellArg(projectDir, 'project dir');
    const safePattern = assertSafeShellArg(pattern, 'grep pattern');
    // shell required: ripgrep/grep with regex and type filtering
    const cmd =
      lang === 'ts'
        ? `grep -rnE --include='*.ts' --include='*.tsx' --include='*.js' --include='*.jsx' -- '${safePattern}' '${safeDir}/src' '${safeDir}/tests' 2>/dev/null | head -${MAX_REFS + 1}`
        : `grep -rnE --include='*.py' -- '${safePattern}' '${safeDir}/src' '${safeDir}/tests' 2>/dev/null | head -${MAX_REFS + 1}`;
    const out = execSync(cmd, { encoding: 'utf8', timeout: 5000 }).trim();
    if (!out) return [];
    return out.split('\n').filter(Boolean).slice(0, MAX_REFS);
  } catch {
    return [];
  }
}

/**
 * Heuristic: the current Write created a new file in a directory that already
 * contains siblings. If any sibling has the same basename as ANY previously-
 * deleted file recorded in .claude/state/recent-deletes.json, we assume this
 * Write is part of a split and those deleted paths are now stale.
 *
 * Without the delete-tracking store, we fall back to: simply checking if any
 * import in the tree references a path where the target no longer exists.
 * That's the cheaper, broader-signal version.
 */
function newFileTriggersSplit(filePath: string): boolean {
  // If parent dir has sibling files with similar stem, likely a split
  const parent = dirname(filePath);
  const stem = basename(filePath).replace(CODE_EXT_RE, '');
  if (!existsSync(parent)) return false;
  // No FS walk — let's stay cheap: return true and let the grep decide.
  return Boolean(stem);
}

export function staleImportDetector(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const toolName = input.tool_name || '';
  if (toolName !== 'Write' && toolName !== 'Edit' && toolName !== 'MultiEdit') {
    return outputSilentSuccess();
  }

  const filePath = getField<string>(input, 'tool_input.file_path') || '';
  if (!filePath || !CODE_EXT_RE.test(filePath)) {
    return outputSilentSuccess();
  }

  // Only interesting if a source file just landed (or was heavily edited)
  if (!newFileTriggersSplit(filePath)) {
    return outputSilentSuccess();
  }

  const { lang, pathHint } = deriveModuleId(ctx.projectDir, filePath);
  if (!lang || !pathHint) return outputSilentSuccess();

  const refs = findStaleReferences(ctx.projectDir, lang, pathHint);
  if (refs.length < MIN_SIGNAL_REFS) return outputSilentSuccess();

  ctx.log(HOOK_NAME, `Found ${refs.length} import references to ${pathHint}`);

  // We do NOT know whether these are stale without a rename/delete tracker.
  // Report as "touch points" to double-check after the edit, rather than as
  // confirmed stale. Low-friction advisory.
  const refsList = refs.map(r => `  - ${r}`).join('\n');
  const message =
    `File ${basename(filePath)} is referenced from ${refs.length} import site(s). ` +
    `If this edit renamed exports or split the file, verify these still resolve:\n${refsList}`;

  return outputNotify(message, { prefix: 'stale-import-detector' });
}
